}
@page
@model Module3_ASP_NET_RazorPage.Pages.Products.CreateModel
@addTagHelper *, Microsoft.AspNetCore.Mvc.TagHelpers

<!DOCTYPE html>
<html lang="vi">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Thêm sản phẩm mới</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            margin: 20px;
            background-color: #f5f5f5;
        }
        .container {
            max-width: 600px;
            margin: 0 auto;
            background-color: white;
            padding: 30px;
            border-radius: 5px;
            box-shadow: 0 0 10px rgba(0,0,0,0.1);
        }
        h1 {
            color: #333;
            border-bottom: 2px solid #0066cc;
            padding-bottom: 10px;
        }
        .toolbar {
            margin-bottom: 20px;
        }
        .btn-back {
            display: inline-block;
            padding: 8px 15px;
            background-color: #6c757d;
            color: white;
            text-decoration: none;
            border-radius: 4px;
            font-size: 0.9em;
        }
        .btn-back:hover {
            background-color: #5a6268;
        }
        .form-group {
            margin-bottom: 15px;
        }
        .form-group label {
            display: block;
            margin-bottom: 5px;
            font-weight: bold;
            color: #333;
        }
        .form-group input[type="text"],
        .form-group input[type="number"],
        .form-group input[type="email"] {
            width: 100%;
            padding: 10px;
            border: 1px solid #ddd;
            border-radius: 4px;
            font-size: 1em;
            box-sizing: border-box;
        }
        .form-group input:focus {
            outline: none;
            border-color: #0066cc;
            box-shadow: 0 0 5px rgba(0, 102, 204, 0.3);
        }
        .form-group input[type="checkbox"] {
            margin-right: 8px;
        }
        .checkbox-label {
            display: flex;
            align-items: center;
        }
        .validation-error {
            color: #dc3545;
            font-size: 0.85em;
            margin-top: 3px;
            display: block;
        }
        .validation-summary {
            background-color: #f8d7da;
            border: 1px solid #f5c6cb;
            color: #721c24;
            padding: 12px;
            border-radius: 4px;
            margin-bottom: 15px;
        }
        .form-actions {
            display: flex;
            gap: 10px;
            margin-top: 25px;
            padding-top: 20px;
            border-top: 1px solid #ddd;
        }
        button {
            flex: 1;
            padding: 12px;
            background-color: #28a745;
            color: white;
            border: none;
            border-radius: 4px;
            cursor: pointer;
            font-weight: bold;
            font-size: 1em;
        }
        button:hover {
            background-color: #218838;
        }
    </style>
</head>
<body>

<div class="container">
    <h1>➕ Thêm sản phẩm mới</h1>

    <div class="toolbar">
        <a href="/Products" class="btn-back">← Quay lại danh sách</a>
    </div>

    <div asp-validation-summary="ModelOnly" class="validation-summary"></div>

    <form method="post">
        <div class="form-group">
            <label asp-for="Product.ProductName">Tên sản phẩm <span style="color:red;">*</span></label>
            <input asp-for="Product.ProductName" placeholder="Nhập tên sản phẩm" />
            <span asp-validation-for="Product.ProductName" class="validation-error"></span>
        </div>

        <div class="form-group">
            <label asp-for="Product.UnitPrice">Giá (đ)</label>
            <input asp-for="Product.UnitPrice" type="number" step="0.01" placeholder="Nhập giá" />
            <span asp-validation-for="Product.UnitPrice" class="validation-error"></span>
        </div>

        <div class="form-group">
            <label asp-for="Product.UnitsInStock">Tồn kho</label>
            <input asp-for="Product.UnitsInStock" type="number" placeholder="Nhập số lượng tồn" />
            <span asp-validation-for="Product.UnitsInStock" class="validation-error"></span>
        </div>

        <div class="form-group">
            <label asp-for="Product.UnitsOnOrder">Số lượng đặt hàng</label>
            <input asp-for="Product.UnitsOnOrder" type="number" placeholder="Nhập số lượng đặt" />
            <span asp-validation-for="Product.UnitsOnOrder" class="validation-error"></span>
        </div>

        <div class="form-group">
            <label asp-for="Product.ReorderLevel">Mức tái đặt hàng</label>
            <input asp-for="Product.ReorderLevel" type="number" placeholder="Nhập mức tái đặt" />
            <span asp-validation-for="Product.ReorderLevel" class="validation-error"></span>
        </div>

        <div class="form-group">
            <label asp-for="Product.QuantityPerUnit">Số lượng trên đơn vị</label>
            <input asp-for="Product.QuantityPerUnit" placeholder="Ví dụ: 10 hộp/thùng" />
            <span asp-validation-for="Product.QuantityPerUnit" class="validation-error"></span>
        </div>

        <div class="form-group">
            <label class="checkbox-label">
                <input asp-for="Product.Discontinued" type="checkbox" />
                <span>Ngừng bán</span>
            </label>
            <span asp-validation-for="Product.Discontinued" class="validation-error"></span>
        </div>

        <div class="form-actions">
            <button type="submit">✓ Thêm sản phẩm</button>
        </div>
    </form>
</div>

</body>
</html>

